import{_ as n,o as s,c as l,a4 as i}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"函数详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-001-函数详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-001-函数详解-V1.0-20260405.md"}'),t={name:"math/Math-Learn-Detail-001-函数详解-V1.0-20260405.md"};function o(p,a,r,e,g,h){return s(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="函数详解" tabindex="-1">函数详解 <a class="header-anchor" href="#函数详解" aria-label="Permalink to &quot;函数详解&quot;">​</a></h1><p><strong>从&quot;对应关系&quot;到&quot;变化模型&quot;</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解函数的本质是&quot;对应关系&quot;</li><li>掌握函数的三大性质（单调性、奇偶性、周期性）</li><li>能用函数模型描述现实世界的变化</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>函数</span></span>
<span class="line"><span>├── 函数概念</span></span>
<span class="line"><span>│   ├── 定义（对应关系）</span></span>
<span class="line"><span>│   ├── 三要素（定义域、值域、对应法则）</span></span>
<span class="line"><span>│   └── 表示方法（解析式、图像、表格）</span></span>
<span class="line"><span>├── 函数性质</span></span>
<span class="line"><span>│   ├── 单调性（增减）⭐</span></span>
<span class="line"><span>│   ├── 奇偶性（对称）⭐</span></span>
<span class="line"><span>│   └── 周期性（循环）</span></span>
<span class="line"><span>├── 基本初等函数</span></span>
<span class="line"><span>│   ├── 幂函数</span></span>
<span class="line"><span>│   ├── 指数函数 ⭐</span></span>
<span class="line"><span>│   ├── 对数函数 ⭐</span></span>
<span class="line"><span>│   └── 指数与对数运算</span></span>
<span class="line"><span>└── 函数应用</span></span>
<span class="line"><span>    ├── 函数零点 ⭐</span></span>
<span class="line"><span>    ├── 函数与方程</span></span>
<span class="line"><span>    └── 函数模型（增长/衰减）</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：初中函数基础、代数运算</li><li><strong>后续应用</strong>：三角函数（周期性）、导数（单调性极值）、数列（离散函数）</li><li><strong>跨学科联系</strong>：物理（运动学）、经济（成本收益模型）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-函数的概念" tabindex="-1">2.1 函数的概念 <a class="header-anchor" href="#_2-1-函数的概念" aria-label="Permalink to &quot;2.1 函数的概念&quot;">​</a></h3><p><strong>一句话定义</strong>：函数是<strong>非空数集之间的对应关系</strong>，满足&quot;每个输入有唯一输出&quot;。</p><p><strong>三要素</strong>：</p><ol><li><strong>定义域</strong>：自变量x的取值范围</li><li><strong>值域</strong>：因变量y的取值范围</li><li><strong>对应法则f</strong>：x→y的对应规则</li></ol><p><strong>关键理解</strong>：</p><ul><li>函数是&quot;关系&quot;，不是&quot;数&quot;</li><li>判断是否为函数：看一个x是否对应唯一y（图像：垂直线检验）</li></ul><p><strong>示例</strong>：</p><ul><li>y = 2x + 1 是函数（线性对应）</li><li>x² + y² = 1 不是函数（一个x对应两个y）</li></ul><hr><h3 id="_2-2-函数的单调性-⭐" tabindex="-1">2.2 函数的单调性 ⭐ <a class="header-anchor" href="#_2-2-函数的单调性-⭐" aria-label="Permalink to &quot;2.2 函数的单调性 ⭐&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li><strong>增函数</strong>：x₁ &lt; x₂ 时，f(x₁) &lt; f(x₂)（图像上升）</li><li><strong>减函数</strong>：x₁ &lt; x₂ 时，f(x₁) &gt; f(x₂)（图像下降）</li></ul><p><strong>判断方法</strong>：</p><ol><li><strong>定义法</strong>：任取x₁ &lt; x₂，比较f(x₁)与f(x₂)</li><li><strong>图像法</strong>：观察图像上升/下降趋势</li><li><strong>导数法</strong>（高二学）：f&#39;(x) &gt; 0 → 增；f&#39;(x) &lt; 0 → 减</li></ol><p><strong>应用</strong>：</p><ul><li>求最值：先找单调区间，再比较端点</li><li>解不等式：利用单调性去掉f</li></ul><hr><h3 id="_2-3-函数的奇偶性-⭐" tabindex="-1">2.3 函数的奇偶性 ⭐ <a class="header-anchor" href="#_2-3-函数的奇偶性-⭐" aria-label="Permalink to &quot;2.3 函数的奇偶性 ⭐&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li><strong>偶函数</strong>：f(-x) = f(x)（图像关于y轴对称）</li><li><strong>奇函数</strong>：f(-x) = -f(x)（图像关于原点对称）</li></ul><p><strong>判断步骤</strong>：</p><ol><li>先看定义域是否关于原点对称（必要条件）</li><li>计算f(-x)</li><li>比较f(-x)与f(x)、-f(x)的关系</li></ol><p><strong>性质</strong>：</p><ul><li>偶 + 偶 = 偶；奇 + 奇 = 奇</li><li>偶 × 偶 = 偶；奇 × 奇 = 偶；奇 × 偶 = 奇</li></ul><hr><h3 id="_2-4-指数与对数" tabindex="-1">2.4 指数与对数 <a class="header-anchor" href="#_2-4-指数与对数" aria-label="Permalink to &quot;2.4 指数与对数&quot;">​</a></h3><p><strong>指数运算</strong>（a &gt; 0，m,n为实数）：</p><ul><li>aᵐ · aⁿ = aᵐ⁺ⁿ</li><li>(aᵐ)ⁿ = aᵐⁿ</li><li>(ab)ⁿ = aⁿbⁿ</li></ul><p><strong>对数定义</strong>：</p><ul><li>若 aˣ = N（a &gt; 0，a ≠ 1），则 x = logₐN</li><li><strong>常用对数</strong>：lg N = log₁₀N</li><li><strong>自然对数</strong>：ln N = logₑN（e ≈ 2.718）</li></ul><p><strong>对数运算</strong>：</p><ul><li>logₐ(MN) = logₐM + logₐN</li><li>logₐ(M/N) = logₐM - logₐN</li><li>logₐMⁿ = n·logₐM</li><li><strong>换底公式</strong>：logₐb = logₙb / logₙa</li></ul><p><strong>指数函数</strong> y = aˣ（a &gt; 0，a ≠ 1）：</p><ul><li>a &gt; 1：单调递增</li><li>0 &lt; a &lt; 1：单调递减</li><li>过定点(0, 1)</li></ul><p><strong>对数函数</strong> y = logₐx（a &gt; 0，a ≠ 1）：</p><ul><li>a &gt; 1：单调递增</li><li>0 &lt; a &lt; 1：单调递减</li><li>过定点(1, 0)</li><li><strong>与指数函数互为反函数</strong></li></ul><hr><h3 id="_2-5-函数零点-⭐" tabindex="-1">2.5 函数零点 ⭐ <a class="header-anchor" href="#_2-5-函数零点-⭐" aria-label="Permalink to &quot;2.5 函数零点 ⭐&quot;">​</a></h3><p><strong>定义</strong>：f(x) = 0 的解，即函数图像与x轴交点的横坐标。</p><p><strong>零点存在定理</strong>：</p><ul><li>若f(x)在[a,b]上连续，且f(a)·f(b) &lt; 0</li><li>则(a,b)内至少有一个零点</li></ul><p><strong>求零点方法</strong>：</p><ol><li><strong>代数法</strong>：解方程f(x) = 0</li><li><strong>图像法</strong>：画y=f(x)看与x轴交点</li><li><strong>二分法</strong>：利用零点存在定理逐步逼近</li></ol><hr><h2 id="三、典型例题" tabindex="-1">三、典型例题 <a class="header-anchor" href="#三、典型例题" aria-label="Permalink to &quot;三、典型例题&quot;">​</a></h2><h3 id="例题1-求函数定义域" tabindex="-1">例题1：求函数定义域 <a class="header-anchor" href="#例题1-求函数定义域" aria-label="Permalink to &quot;例题1：求函数定义域&quot;">​</a></h3><p><strong>题目</strong>：求f(x) = √(x+1) + ln(2-x)的定义域</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>要使f(x)有意义，需要：</span></span>
<span class="line"><span>① x + 1 ≥ 0  →  x ≥ -1</span></span>
<span class="line"><span>② 2 - x &gt; 0  →  x &lt; 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>取交集：-1 ≤ x &lt; 2</span></span>
<span class="line"><span>∴ 定义域为[-1, 2)</span></span></code></pre></div><p><strong>关键点</strong>：</p><ul><li>偶次根号下≥0</li><li>对数真数&gt;0</li><li>分母≠0（本题无分母）</li></ul><hr><h3 id="例题2-判断函数奇偶性" tabindex="-1">例题2：判断函数奇偶性 <a class="header-anchor" href="#例题2-判断函数奇偶性" aria-label="Permalink to &quot;例题2：判断函数奇偶性&quot;">​</a></h3><p><strong>题目</strong>：判断f(x) = x³ - 2x的奇偶性</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一步：看定义域</span></span>
<span class="line"><span>定义域为R，关于原点对称 ✓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二步：计算f(-x)</span></span>
<span class="line"><span>f(-x) = (-x)³ - 2(-x) = -x³ + 2x = -(x³ - 2x) = -f(x)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三步：判断</span></span>
<span class="line"><span>∵ f(-x) = -f(x)</span></span>
<span class="line"><span>∴ f(x)是奇函数</span></span></code></pre></div><p><strong>关键点</strong>：</p><ul><li>先看定义域是否对称</li><li>多项式函数：偶次幂→偶，奇次幂→奇</li></ul><hr><h3 id="例题3-指数对数运算" tabindex="-1">例题3：指数对数运算 <a class="header-anchor" href="#例题3-指数对数运算" aria-label="Permalink to &quot;例题3：指数对数运算&quot;">​</a></h3><p><strong>题目</strong>：计算 (1/4)⁻² + log₂3 · log₃4</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1/4)⁻² = 4² = 16</span></span>
<span class="line"><span></span></span>
<span class="line"><span>log₂3 · log₃4 = log₂3 · (log₂4 / log₂3)  【换底公式】</span></span>
<span class="line"><span>               = log₂4</span></span>
<span class="line"><span>               = 2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ 原式 = 16 + 2 = 18</span></span></code></pre></div><p><strong>关键点</strong>：</p><ul><li>负指数：a⁻ⁿ = 1/aⁿ</li><li>换底公式：logₐb · log_bc = logₐc（链式法则）</li></ul><hr><h2 id="四、配套练习" tabindex="-1">四、配套练习 <a class="header-anchor" href="#四、配套练习" aria-label="Permalink to &quot;四、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：求下列函数的定义域</p><ul><li>(1) f(x) = √(2x-1) / (x-3)</li><li>(2) f(x) = ln(x+2) + √(4-x)</li></ul><p><strong>练习2</strong>：判断下列函数的奇偶性</p><ul><li>(1) f(x) = x⁴ - 2x² + 1</li><li>(2) f(x) = x + 1/x</li></ul><p><strong>练习3</strong>：计算</p><ul><li>(1) 8^(2/3) + log₂6 - log₂3</li><li>(2) log₃5 · log₅9</li></ul><p><strong>参考答案</strong>：</p><ul><li>练习1：(1) [1/2, 3)∪(3, +∞)；(2) (-2, 4]</li><li>练习2：(1) 偶函数；(2) 奇函数</li><li>练习3：(1) 5；(2) 2</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习4</strong>：已知f(x)是奇函数，当x &gt; 0时f(x) = x(1+x)，求x &lt; 0时的表达式。</p><p><strong>练习5</strong>：函数f(x) = aˣ + logₐ(x+1)在[0,1]上的最大值与最小值之和为a，求a的值。</p><hr><h2 id="五、faq常见问题" tabindex="-1">五、FAQ常见问题 <a class="header-anchor" href="#五、faq常见问题" aria-label="Permalink to &quot;五、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-我求定义域时总是漏条件" tabindex="-1">FAQ 1：我求定义域时总是漏条件 <a class="header-anchor" href="#faq-1-我求定义域时总是漏条件" aria-label="Permalink to &quot;FAQ 1：我求定义域时总是漏条件&quot;">​</a></h3><p><strong>错误示例</strong>：</p><ul><li>只考虑根号下≥0，忘了分母≠0</li><li>只考虑对数真数&gt;0，忘了根号下≥0</li></ul><p><strong>正确做法</strong>：</p><ul><li>建立检查清单：看到根号→≥0；看到对数→&gt;0；看到分母→≠0</li><li>所有条件取<strong>交集</strong></li></ul><hr><h3 id="faq-2-指数对数运算总出错" tabindex="-1">FAQ 2：指数对数运算总出错 <a class="header-anchor" href="#faq-2-指数对数运算总出错" aria-label="Permalink to &quot;FAQ 2：指数对数运算总出错&quot;">​</a></h3><p><strong>常见错误</strong>：</p><ul><li>(aᵐ)ⁿ ≠ a^(mⁿ) 而是 a^(m·n)</li><li>logₐ(M+N) ≠ logₐM + logₐN（对数没有分配律）</li></ul><p><strong>记忆技巧</strong>：</p><ul><li>指数：相乘→指数相加；幂的幂→指数相乘</li><li>对数：真数相乘→对数相加；真数相除→对数相减</li></ul><hr><h3 id="faq-3-判断奇偶性时总忘看定义域" tabindex="-1">FAQ 3：判断奇偶性时总忘看定义域 <a class="header-anchor" href="#faq-3-判断奇偶性时总忘看定义域" aria-label="Permalink to &quot;FAQ 3：判断奇偶性时总忘看定义域&quot;">​</a></h3><p><strong>错误示例</strong>： f(x) = x²，x∈[0, +∞)，说它是偶函数</p><p><strong>正确做法</strong>：</p><ul><li>先看定义域是否关于原点对称（即若x在定义域，-x也在）</li><li>[0, +∞)不对称，所以<strong>非奇非偶</strong></li></ul><hr><h3 id="faq-4-对数换底公式记不住" tabindex="-1">FAQ 4：对数换底公式记不住 <a class="header-anchor" href="#faq-4-对数换底公式记不住" aria-label="Permalink to &quot;FAQ 4：对数换底公式记不住&quot;">​</a></h3><p><strong>推导帮助记忆</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设 logₐb = x，则 aˣ = b</span></span>
<span class="line"><span>两边取以n为底的对数：logₙ(aˣ) = logₙb</span></span>
<span class="line"><span>x · logₙa = logₙb</span></span>
<span class="line"><span>x = logₙb / logₙa</span></span>
<span class="line"><span>∴ logₐb = logₙb / logₙa</span></span></code></pre></div><hr><h2 id="六、本章检查清单" tabindex="-1">六、本章检查清单 <a class="header-anchor" href="#六、本章检查清单" aria-label="Permalink to &quot;六、本章检查清单&quot;">​</a></h2><ul><li>[ ] 能准确复述函数的定义和三要素</li><li>[ ] 能求常见函数的定义域（根号、对数、分母组合）</li><li>[ ] 能判断函数的单调性（定义法/图像法）</li><li>[ ] 能判断函数的奇偶性（先看定义域对称性）</li><li>[ ] 熟练掌握指数对数运算公式</li><li>[ ] 理解函数零点的概念和零点存在定理</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-001<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,120)])])}const d=n(t,[["render",o]]);export{u as __pageData,d as default};
